code = """import json
import os

# Load the article dataset
file_path = locals()['var_functions.query_db:32']
with open(file_path, 'r') as f:
    all_articles = json.load(f)

# Check how many articles total
print('Total articles in dataset: %d' % len(all_articles))

# Look at first 50 titles to see what categories exist
print('\nFirst 50 titles:')
for i in range(min(50, len(all_articles))):
    print('%d. %s' % (i+1, all_articles[i]['title']))

# Search more systematically for sports content
print('\n=== SEARCHING FOR SPORTS CONTENT ===')

# List of sports-related terms (comprehensive)
sports_terms = [
    'sport', 'football', 'soccer', 'basketball', 'baseball', 'tennis', 'golf',
    'cricket', 'rugby', 'hockey', 'volleyball', 'boxing', 'wrestling',
    'athlete', 'athletics', 'coach', 'player', 'team', 'game', 'match',
    'championship', 'tournament', 'competition', 'race', 'racing', 'marathon',
    'olympic', 'olympics', 'medal', 'victory', 'defeat', 'score', 'season',
    'league', 'quarterback', 'pitcher', 'striker', 'goalkeeper', 'batter',
    'grand prix', 'formula 1', 'f1', 'world cup'
]

# Check each article
sports_articles = []

for idx, article in enumerate(all_articles):
    title_lower = article['title'].lower()
    desc_lower = article['description'].lower()
    combined = title_lower + ' ' + desc_lower
    
    # Count how many sports terms appear
    found_terms = []
    for term in sports_terms:
        if term in combined:
            found_terms.append(term)
    
    if len(found_terms) > 0:
        sports_articles.append({
            'index': idx,
            'title': article['title'],
            'found_terms': found_terms,
            'desc_length': len(article['description'])
        })

print('Total articles with sports terms: %d' % len(sports_articles))

if sports_articles:
    print('\nTop 10 sports articles by description length:')
    # Sort by description length (descending)
    sports_articles.sort(key=lambda x: x['desc_length'], reverse=True)
    
    for i, article in enumerate(sports_articles[:10]):
        print('%d. "%s" (length: %d, terms: %s)' % (
            i+1, article['title'][:70], article['desc_length'], ', '.join(article['found_terms'])))
    
    # Get the answer
    answer = sports_articles[0]['title']
else:
    answer = 'No sports articles found'
    print('\nNo sports articles could be identified in the dataset')

print('\nFINAL ANSWER: %s' % answer)
print('__RESULT__:')
print(json.dumps(answer))"""

